import { CheckboxButton, CheckboxField, FieldError } from "react-aria-components"
import { getCheckboxStyles } from "./checkbox.styles"

interface CheckboxProps {
	readonly label?: string
	readonly value?: string
	readonly name?: string
	readonly isSelected?: boolean
	readonly defaultSelected?: boolean
	readonly isDisabled?: boolean
	readonly isRequired?: boolean
	readonly isReadOnly?: boolean
	readonly isIndeterminate?: boolean
	readonly isInvalid?: boolean
	readonly autoFocus?: boolean
	readonly validationBehavior?: "aria" | "native"
	readonly validate?: (value: boolean) => string | string[] | true | null | undefined
	readonly errorMessage?: string
	readonly onChange?: (isSelected: boolean) => void
}

export function Checkbox({
	label,
	value,
	name,
	isSelected,
	defaultSelected,
	isDisabled = false,
	isRequired = false,
	isReadOnly = false,
	isIndeterminate = false,
	isInvalid = false,
	autoFocus,
	validationBehavior,
	validate,
	errorMessage,
	onChange,
}: CheckboxProps) {
	const styles = getCheckboxStyles()

	return (
		<CheckboxField
			value={value}
			name={name}
			isSelected={isSelected}
			defaultSelected={defaultSelected}
			isDisabled={isDisabled}
			isRequired={isRequired}
			isReadOnly={isReadOnly}
			isIndeterminate={isIndeterminate}
			isInvalid={isInvalid}
			autoFocus={autoFocus}
			validationBehavior={validationBehavior}
			validate={validate}
			onChange={onChange}
			className={styles.field}
		>
			<CheckboxButton
				className={({ isDisabled: dis, isInvalid: inv }) =>
					`${styles.button} ${dis ? "cursor-not-allowed opacity-50" : ""} ${inv ? "text-(--color-danger)" : ""}`
				}
			>
				{({ isSelected: sel, isIndeterminate: indet, isDisabled: dis, isInvalid: inv }) => (
					<>
						<div
							className={styles.indicator({ isSelected: sel, isIndeterminate: indet, isDisabled: dis, isInvalid: inv })}
						>
							{(sel || indet) && (
								<svg viewBox="0 0 12 12" aria-hidden="true" className="h-3 w-3">
									{indet ? (
										<rect x={1} y={5} width={10} height={2} fill="currentColor" />
									) : (
										<polyline
											points="1.5 6 4.5 9.5 10.5 2.5"
											fill="none"
											stroke="currentColor"
											strokeWidth={2}
											strokeLinecap="round"
											strokeLinejoin="round"
										/>
									)}
								</svg>
							)}
						</div>
						{label}
					</>
				)}
			</CheckboxButton>
			<FieldError className={styles.errorMessage}>
				{({ validationErrors }) => errorMessage ?? validationErrors.join(", ")}
			</FieldError>
		</CheckboxField>
	)
}

import type { ReactNode } from "react"
import { FieldError, Label, CheckboxGroup as RACCheckboxGroup, Text } from "react-aria-components"
import { getCheckboxGroupStyles } from "./checkbox.styles"

interface CheckboxGroupProps {
	readonly label?: string
	readonly value?: string[]
	readonly defaultValue?: string[]
	readonly isDisabled?: boolean
	readonly isRequired?: boolean
	readonly isReadOnly?: boolean
	readonly isInvalid?: boolean
	readonly validationBehavior?: "aria" | "native"
	readonly validate?: (value: string[]) => string | string[] | true | null | undefined
	readonly orientation?: "horizontal" | "vertical"
	readonly name?: string
	readonly description?: string
	readonly errorMessage?: string
	readonly onChange?: (value: string[]) => void
	readonly children?: ReactNode
}

export function CheckboxGroup({
	label,
	value,
	defaultValue,
	isDisabled = false,
	isRequired = false,
	isReadOnly = false,
	isInvalid = false,
	validationBehavior,
	validate,
	orientation = "vertical",
	name,
	description,
	errorMessage,
	onChange,
	children,
}: CheckboxGroupProps) {
	const styles = getCheckboxGroupStyles()

	return (
		<RACCheckboxGroup
			value={value}
			defaultValue={defaultValue}
			isDisabled={isDisabled}
			isRequired={isRequired}
			isReadOnly={isReadOnly}
			isInvalid={isInvalid}
			validationBehavior={validationBehavior}
			validate={validate}
			name={name}
			onChange={onChange}
			className={styles.group}
		>
			{label && <Label className={styles.label}>{label}</Label>}
			<div className={styles.items(orientation)}>{children}</div>
			{description && (
				<Text slot="description" className={styles.description}>
					{description}
				</Text>
			)}
			<FieldError className={styles.errorMessage}>{errorMessage}</FieldError>
		</RACCheckboxGroup>
	)
}

interface IndicatorState {
	isSelected: boolean
	isIndeterminate: boolean
	isDisabled?: boolean
	isInvalid?: boolean
}

const indicatorBase = "w-4 h-4 shrink-0 rounded border-2 flex items-center justify-center transition-colors"

export const getCheckboxStyles = () => ({
	field: "flex flex-col gap-1",
	button: "flex items-center gap-2 text-sm text-(--color-text) cursor-pointer select-none",
	description: "text-xs text-(--color-text-muted)",
	errorMessage: "text-xs text-(--color-danger)",
	indicator({ isSelected, isIndeterminate, isDisabled, isInvalid }: IndicatorState) {
		if (isDisabled) {
			return `${indicatorBase} bg-(--color-background-muted) border-(--color-border) opacity-50`
		}
		if (isInvalid) {
			return `${indicatorBase} bg-(--color-background) border-(--color-danger)`
		}
		if (isSelected || isIndeterminate) {
			return `${indicatorBase} bg-(--color-primary) border-(--color-primary) text-(--color-primary-foreground)`
		}
		return `${indicatorBase} bg-(--color-background) border-(--color-border)`
	},
})

export const getCheckboxGroupStyles = () => ({
	group: "flex flex-col gap-2",
	label: "text-sm font-medium text-(--color-text)",
	items: (orientation: "horizontal" | "vertical" = "vertical") =>
		orientation === "horizontal" ? "flex flex-row flex-wrap gap-4" : "flex flex-col gap-2",
	description: "text-xs text-(--color-text-muted)",
	errorMessage: "text-xs text-(--color-danger)",
})
